import { useMemo, useState } from 'react';
import { View, Text, StyleSheet, ScrollView, TouchableOpacity, Alert, ActivityIndicator } from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import { router } from 'expo-router';
import { Ionicons } from '@expo/vector-icons';
import { Colors } from '../../constants/Colors';
import { useAuthStore } from '@/store/authStore';
import api from '@/services/api';
import { useAppTranslation, useLanguage } from '../../context/LanguageContext';
import { useTheme } from '../../context/ThemeContext';
import { PageHeader } from '@/components/ui/page-header';

type ListingType = 'CAR' | 'PLATE' | 'PART' | 'MOTORCYCLE';

interface TypeOption {
  type: ListingType;
  title: string;
  summary: string;
  fields: string;
  icon: keyof typeof Ionicons.glyphMap;
}

const typeOptions: TypeOption[] = [
  { type: 'CAR', title: '', summary: '', fields: '', icon: 'car-sport' },
  { type: 'MOTORCYCLE', title: '', summary: '', fields: '', icon: 'bicycle' },
  { type: 'PLATE', title: '', summary: '', fields: '', icon: 'document-text' },
  { type: 'PART', title: '', summary: '', fields: '', icon: 'settings' },
];

export default function AddListingScreen() {
  const { user, isAuthenticated } = useAuthStore();
  const { t } = useAppTranslation();
  const { isRTL } = useLanguage();
  const { isDark } = useTheme();
  const [selectedType, setSelectedType] = useState<ListingType | null>(null);
  const [isCreating, setIsCreating] = useState(false);

  const localizedTypeOptions: TypeOption[] = useMemo(() => [
    { type: 'CAR', title: t('addHub.carTitle'), summary: t('addHub.carSummary'), fields: t('addHub.carFields'), icon: 'car-sport' },
    { type: 'MOTORCYCLE', title: t('addHub.motorcycleTitle'), summary: t('addHub.motorcycleSummary'), fields: t('addHub.motorcycleFields'), icon: 'bicycle' },
    { type: 'PLATE', title: t('addHub.plateTitle'), summary: t('addHub.plateSummary'), fields: t('addHub.plateFields'), icon: 'document-text' },
    { type: 'PART', title: t('addHub.partTitle'), summary: t('addHub.partSummary'), fields: t('addHub.partFields'), icon: 'settings' },
  ], [t]);

  const selectedOption = useMemo(
    () => localizedTypeOptions.find((option) => option.type === selectedType) ?? localizedTypeOptions[0],
    [localizedTypeOptions, selectedType]
  );

  const theme = {
    background: isDark ? Colors.dark.background : Colors.background,
    card: isDark ? Colors.dark.surface : Colors.surface,
    text: isDark ? Colors.dark.text : Colors.text,
    textMuted: isDark ? '#94a3b8' : Colors.textSecondary,
    border: isDark ? '#1f2937' : Colors.border,
    primary: Colors.primary,
  };

  const dirText = { textAlign: 'auto' as const};
  const rowDirection = { flexDirection: 'row' as const };

  const getDraftTitle = (type: ListingType) => {
    switch (type) {
      case 'CAR':
        return t('addHub.draftCar');
      case 'MOTORCYCLE':
        return t('addHub.draftMotorcycle');
      case 'PLATE':
        return t('addHub.draftPlate');
      case 'PART':
        return t('addHub.draftPart');
      default:
        return t('addHub.draftGeneric');
    }
  };

  const handleStart = async () => {
    const type = selectedType ?? 'CAR';
    if (!isAuthenticated) {
      Alert.alert(
        t('addHub.loginRequiredTitle'),
        t('addHub.loginRequiredMessage'),
        [
          { text: t('common.cancel'), style: 'cancel' },
          { text: t('auth.login'), onPress: () => router.push('/(auth)/login') },
        ]
      );
      return;
    }

    setIsCreating(true);
    try {
      const response = await api.post('/listings', {
        type,
        title: getDraftTitle(type),
        price: 0,
        currency: 'BHD',
      });

      const listingId = response.data.data.id;

      router.push({ pathname: '/add-listing/[id]', params: { id: listingId, type } });
    } catch (error: any) {
      console.error('Failed to create draft listing:', error);
      Alert.alert(t('common.error'), error.response?.data?.message || t('addHub.startCreateFailed'), [{ text: t('common.ok') }]);
    } finally {
      setIsCreating(false);
    }
  };

  return (
    <SafeAreaView edges={['left', 'right', 'bottom']} style={[styles.container, { backgroundColor: theme.background }]}>
      <PageHeader
        title={t('addHub.addNewListing')}
        variant="gradient"
      />
      <ScrollView contentContainerStyle={styles.scrollContent}>
        <View style={[styles.heroCard, { backgroundColor: theme.card, borderColor: theme.border }]}> 
          <Text style={[styles.heroTitle, { color: theme.text }, dirText]}>{t('addHub.chooseTypeTitle')}</Text>
          <Text style={[styles.heroDescription, { color: theme.textMuted }, dirText]}>{t('addHub.chooseTypeDescription')}</Text>
        </View>

        <View style={[styles.chipsContainer, rowDirection]}>
          {localizedTypeOptions.map((option) => (
            <TouchableOpacity
              key={option.type}
              style={[
                styles.typeChip,
                { backgroundColor: theme.card, borderColor: theme.border },
                (selectedType ?? 'CAR') === option.type && [styles.typeChipActive, { borderColor: theme.primary, backgroundColor: isDark ? '#0b1835' : '#eff6ff' }],
              ]}
              onPress={() => setSelectedType(option.type)}
              disabled={isCreating}
            >
              <Ionicons
                name={option.icon}
                size={18}
                color={(selectedType ?? 'CAR') === option.type ? theme.primary : theme.textMuted}
              />
              <Text style={[styles.typeChipText, { color: (selectedType ?? 'CAR') === option.type ? theme.primary : theme.text }, dirText]}>{option.title}</Text>
            </TouchableOpacity>
          ))}
        </View>

        <View style={[styles.previewCard, { backgroundColor: theme.card, borderColor: theme.border }]}> 
          <Text style={[styles.previewTitle, { color: theme.text }, dirText]}>{selectedOption.title}</Text>
          <Text style={[styles.previewSummary, { color: theme.textMuted }, dirText]}>{selectedOption.summary}</Text>
          <Text style={[styles.previewFieldsLabel, { color: theme.text }, dirText]}>{t('addHub.basicFieldsLabel')}</Text>
          <Text style={[styles.previewFields, { color: theme.textMuted }, dirText]}>{selectedOption.fields}</Text>
        </View>

        <TouchableOpacity
          style={[styles.startButton, { backgroundColor: theme.primary }, rowDirection, isCreating && styles.startButtonDisabled]}
          onPress={handleStart}
          disabled={isCreating}
        >
          {isCreating ? (
            <ActivityIndicator size="small" color="#FFFFFF" />
          ) : (
            <>
              <Ionicons name={isRTL ? 'arrow-forward' : 'arrow-back'} size={18} color="#FFFFFF" />
              <Text style={[styles.startButtonText, dirText]}>{t('addHub.startAdding', { type: selectedOption.title })}</Text>
            </>
          )}
        </TouchableOpacity>
      </ScrollView>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: Colors.background,
  },
  scrollContent: {
    padding: 20,
    gap: 16,
  },
  heroCard: {
    borderWidth: 1,
    borderRadius: 18,
    padding: 18,
  },
  heroTitle: {
    fontSize: 22,
    fontWeight: '700',
    width: '100%',
    marginBottom: 8,
  },
  heroDescription: {
    fontSize: 15,
    lineHeight: 24,
    width: '100%',
  },
  chipsContainer: {
    flexDirection: 'row',
    flexWrap: 'wrap',
    gap: 10,
    justifyContent: 'flex-end',
  },
  typeChip: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'flex-end',
    gap: 8,
    borderWidth: 1,
    borderRadius: 999,
    paddingHorizontal: 16,
    paddingVertical: 12,
  },
  typeChipActive: {
    borderWidth: 1.5,
  },
  typeChipText: {
    fontSize: 15,
    fontWeight: '600',
  },
  previewCard: {
    borderWidth: 1,
    borderRadius: 18,
    padding: 18,
  },
  previewTitle: {
    fontSize: 20,
    fontWeight: '700',
    width: '100%',
    marginBottom: 6,
  },
  previewSummary: {
    fontSize: 14,
    lineHeight: 22,
    marginBottom: 14,
    width: '100%',
  },
  previewFieldsLabel: {
    fontSize: 14,
    fontWeight: '700',
    marginBottom: 6,
    width: '100%',
  },
  previewFields: {
    fontSize: 14,
    lineHeight: 22,
    width: '100%',
  },
  startButton: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'center',
    gap: 10,
    borderRadius: 16,
    paddingVertical: 16,
    marginTop: 4,
  },
  startButtonDisabled: {
    opacity: 0.7,
  },
  startButtonText: {
    color: '#FFFFFF',
    fontSize: 16,
    fontWeight: '700',
  },
});

import React, { useEffect, useState, useCallback, useRef, useLayoutEffect } from 'react';
import {
  View,
  StyleSheet,
  FlatList,
  Text,
  ActivityIndicator,
  Dimensions,
  ViewToken,
  TouchableOpacity,
  Modal,
} from 'react-native';
import { useIsFocused } from '@react-navigation/native';
import { useNavigation } from '@react-navigation/native';
import { useLocalSearchParams, useRouter } from 'expo-router';
import { Ionicons } from '@expo/vector-icons';
import { LinearGradient } from 'expo-linear-gradient';
import { Image } from 'expo-image';
import { StatusBar } from 'expo-status-bar';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { PageHeader } from '../../components/ui/page-header';
import { useAppTranslation, useLanguage } from '../../context/LanguageContext';
import api from '../../services/api';
import VideoFeedItem from '../../components/feed/VideoFeedItem';
import StoryViewer from '../../components/stories/StoryViewer';
import type { StoryUser } from '../../components/stories/StoriesRail';

const { height: SCREEN_HEIGHT, width: SCREEN_WIDTH } = Dimensions.get('window');
const GRID_COLS = 2;
const GRID_GAP = 3;
const THUMB_WIDTH = (SCREEN_WIDTH - GRID_GAP * (GRID_COLS + 1)) / GRID_COLS;
const THUMB_HEIGHT = THUMB_WIDTH * 1.6;

// ??? Story Circle ????????????????????????????????????????????????
function StoryCircle({ user, onPress, fallbackName }: { user: StoryUser; onPress: () => void; fallbackName: string }) {
  const avatar = user.stories?.[0]?.mediaUrl ?? null;
  return (
    <TouchableOpacity style={sc.storyItem} onPress={onPress} activeOpacity={0.8}>
      <LinearGradient colors={['#D4AF37', '#C9A227', '#997D2D']} style={sc.storyRing}>
        <View style={sc.storyAvatarWrapper}>
          {avatar ? (
            <Image source={{ uri: avatar }} style={sc.storyAvatar} contentFit="cover" />
          ) : (
            <View style={[sc.storyAvatar, { backgroundColor: '#1a2a50', justifyContent: 'center', alignItems: 'center' }]}>
              <Ionicons name="person" size={20} color="#D4AF37" />
            </View>
          )}
        </View>
      </LinearGradient>
      <Text style={sc.storyName} numberOfLines={1}>
        {user.userName ?? fallbackName}
      </Text>
    </TouchableOpacity>
  );
}

const sc = StyleSheet.create({
  storyItem: { alignItems: 'center', marginHorizontal: 6, width: 72 },
  storyRing: { width: 70, height: 70, borderRadius: 35, padding: 2.5 },
  storyAvatarWrapper: { flex: 1, borderRadius: 32, overflow: 'hidden', borderWidth: 2, borderColor: '#0E1830' },
  storyAvatar: { width: '100%', height: '100%' },
  storyName: { color: '#D4AF37', fontSize: 10, marginTop: 4, textAlign: 'center', maxWidth: 68 },
});

// ??? Fullscreen Reels Modal ???????????????????????????????????????
function ReelsModal({
  visible,
  videos,
  startIndex,
  isFocused,
  onClose,
}: {
  visible: boolean;
  videos: any[];
  startIndex: number;
  isFocused: boolean;
  onClose: () => void;
}) {
  const [activeIndex, setActiveIndex] = useState(startIndex);
  const [listHeight, setListHeight] = useState(SCREEN_HEIGHT);
  const flatRef = useRef<FlatList>(null);
  const insets = useSafeAreaInsets();

  useEffect(() => {
    if (visible) {
      setActiveIndex(startIndex);
      setTimeout(() => {
        flatRef.current?.scrollToIndex({ index: startIndex, animated: false });
      }, 50);
    }
  }, [visible, startIndex]);

  const onViewableItemsChanged = useRef(({ viewableItems }: { viewableItems: ViewToken[] }) => {
    if (viewableItems.length > 0) setActiveIndex(viewableItems[0].index ?? 0);
  });
  const viewabilityConfig = useRef({ itemVisiblePercentThreshold: 60 });

  const renderItem = useCallback(({ item, index }: { item: any; index: number }) => (
    <VideoFeedItem
      video={item}
      isActive={visible && isFocused && index === activeIndex}
      height={listHeight}
    />
  ), [visible, isFocused, activeIndex, listHeight]);

  return (
    <Modal visible={visible} animationType="slide" onRequestClose={onClose}>
      <View style={{ flex: 1, backgroundColor: '#000', paddingTop: insets.top }}>
        <StatusBar style="light" />
        <View style={{ flex: 1 }} onLayout={(e) => setListHeight(e.nativeEvent.layout.height)}>
          <FlatList
            ref={flatRef}
            data={videos}
            keyExtractor={(item: any) => item.id}
            renderItem={renderItem}
            pagingEnabled
            snapToInterval={listHeight}
            snapToAlignment="start"
            decelerationRate="fast"
            showsVerticalScrollIndicator={false}
            onViewableItemsChanged={onViewableItemsChanged.current}
            viewabilityConfig={viewabilityConfig.current}
            getItemLayout={(_, index) => ({
              length: listHeight,
              offset: listHeight * index,
              index,
            })}
          />
        </View>
        {/* Close button */}
        <TouchableOpacity
          style={[s.closeBtn, { top: insets.top + 10 }]}
          onPress={onClose}
        >
          <Ionicons name="close" size={26} color="#fff" />
        </TouchableOpacity>
      </View>
    </Modal>
  );
}

// ??? Video Thumbnail Card ?????????????????????????????????????????
function VideoThumb({ item, onPress }: { item: any; onPress: () => void }) {
  const thumb = item.thumbnailUrl ?? item.thumbnail ?? null;
  return (
    <TouchableOpacity style={s.thumbCard} onPress={onPress} activeOpacity={0.85}>
      {thumb ? (
        <Image source={{ uri: thumb }} style={s.thumbImage} contentFit="cover" />
      ) : (
        <View style={[s.thumbImage, s.thumbPlaceholder]}>
          <Ionicons name="videocam" size={28} color="#D4AF37" />
        </View>
      )}
      <LinearGradient colors={['transparent', 'rgba(0,0,0,0.7)']} style={s.thumbGradient} />
      <View style={s.playIcon}>
        <Ionicons name="play-circle" size={32} color="rgba(255,255,255,0.9)" />
      </View>
      {item.title ? (
        <Text style={s.thumbTitle} numberOfLines={2}>{item.title}</Text>
      ) : null}
    </TouchableOpacity>
  );
}

// ??? Main Component ??????????????????????????????????????????????
export default function Feed() {
  const isFocused = useIsFocused();
  const navigation = useNavigation();
  const router = useRouter();
  const { storyId } = useLocalSearchParams<{ storyId?: string }>();
  const { t } = useAppTranslation();

  useLayoutEffect(() => {
    navigation.getParent()?.setOptions({ tabBarStyle: { display: 'none' } });
    return () => navigation.getParent()?.setOptions({ tabBarStyle: undefined });
  }, [navigation]);

  const [videos, setVideos] = useState<any[]>([]);
  const [stories, setStories] = useState<StoryUser[]>([]);
  const [loading, setLoading] = useState(false);
  const [storyViewerVisible, setStoryViewerVisible] = useState(false);
  const [storyInitialIndex, setStoryInitialIndex] = useState(0);
  const [initialStoryId, setInitialStoryId] = useState<string | undefined>(undefined);
  const [handledStoryId, setHandledStoryId] = useState<string | null>(null);
  const [reelsVisible, setReelsVisible] = useState(false);
  const [reelsStartIndex, setReelsStartIndex] = useState(0);

  const loadData = useCallback(async () => {
    setLoading(true);
    try {
      const [videosRes, storiesRes] = await Promise.all([
        api.get('/admin-videos'),
        api.get('/stories/feed'),
      ]);
      const raw = videosRes.data?.data ?? videosRes.data ?? [];
      setVideos(Array.isArray(raw) ? raw : []);
      const rawStories = storiesRes.data?.data ?? storiesRes.data ?? [];
      setStories(Array.isArray(rawStories) ? rawStories : []);
    } catch (e) {
      console.error('[Feed] load error', e);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  useEffect(() => {
    if (!storyId || handledStoryId === storyId || stories.length === 0) {
      return;
    }

    const matchingUserIndex = stories.findIndex((storyUser) =>
      Array.isArray(storyUser.stories) && storyUser.stories.some((story) => story?.id === storyId)
    );

    setHandledStoryId(storyId);

    if (matchingUserIndex === -1) {
      return;
    }

    setStoryInitialIndex(matchingUserIndex);
    setInitialStoryId(storyId);
    setStoryViewerVisible(true);
  }, [storyId, handledStoryId, stories]);

  const openReels = (index: number) => {
    setReelsStartIndex(index);
    setReelsVisible(true);
  };

  const StoriesRow = useCallback(() => {
    if (stories.length === 0) return null;
    return (
      <View style={s.storiesBar}>
        <FlatList
          horizontal
          data={stories}
          keyExtractor={(item: any) => item.userId ?? item.id ?? Math.random().toString()}
          contentContainerStyle={{ paddingHorizontal: 10, paddingVertical: 6 }}
          showsHorizontalScrollIndicator={false}
          renderItem={({ item, index }) => (
            <StoryCircle
              user={item}
              fallbackName={t('feed.defaultStoryUser')}
              onPress={() => {
                setInitialStoryId(undefined);
                setStoryInitialIndex(index);
                setStoryViewerVisible(true);
              }}
            />
          )}
        />
      </View>
    );
  }, [stories]);

  return (
    <View style={s.root}>
      <StatusBar style="light" />

      <PageHeader
        title={t('feed.title')}
        showBack={true}
        onBack={() => router.replace('/(tabs)')}
        variant="gradient"
      />

      {loading ? (
        <View style={s.centered}>
          <ActivityIndicator size="large" color="#D4AF37" />
        </View>
      ) : (
        <FlatList
          data={videos}
          keyExtractor={(item: any) => item.id}
          numColumns={GRID_COLS}
          ListHeaderComponent={<StoriesRow />}
          columnWrapperStyle={s.row}
          contentContainerStyle={{ paddingHorizontal: GRID_GAP, paddingBottom: 20 }}
          showsVerticalScrollIndicator={false}
          renderItem={({ item, index }) => (
            <VideoThumb item={item} onPress={() => openReels(index)} />
          )}
          ListEmptyComponent={() => (
            <View style={s.centered}>
              <Ionicons name="videocam-outline" size={52} color="rgba(255,255,255,0.3)" />
              <Text style={[s.emptyText, { textAlign: 'auto'}]}>{t('feed.empty')}</Text>
            </View>
          )}
        />
      )}

      {/* Fullscreen Reels */}
      <ReelsModal
        visible={reelsVisible}
        videos={videos}
        startIndex={reelsStartIndex}
        isFocused={isFocused}
        onClose={() => setReelsVisible(false)}
      />

      <StoryViewer
        visible={storyViewerVisible}
        storyUsers={stories}
        initialUserIndex={storyInitialIndex}
        initialStoryId={initialStoryId}
        onClose={() => {
          setStoryViewerVisible(false);
          setInitialStoryId(undefined);
        }}
      />
    </View>
  );
}

const s = StyleSheet.create({
  root: { flex: 1, backgroundColor: '#111' },
  centered: { flex: 1, justifyContent: 'center', alignItems: 'center', paddingTop: 60 },
  emptyText: { color: 'rgba(255,255,255,0.4)', fontSize: 14, marginTop: 12 },
  storiesBar: {
    backgroundColor: '#000',
    borderBottomWidth: 0.5,
    borderBottomColor: '#1a1a1a',
    marginBottom: 6,
  },
  row: {
    gap: GRID_GAP,
    marginBottom: GRID_GAP,
  },
  thumbCard: {
    width: THUMB_WIDTH,
    height: THUMB_HEIGHT,
    borderRadius: 8,
    overflow: 'hidden',
    backgroundColor: '#1a1a1a',
  },
  thumbImage: { width: '100%', height: '100%' },
  thumbPlaceholder: { justifyContent: 'center', alignItems: 'center' },
  thumbGradient: {
    position: 'absolute',
    bottom: 0,
    left: 0,
    right: 0,
    height: '50%',
  },
  playIcon: {
    position: 'absolute',
    top: '50%',
    left: '50%',
    transform: [{ translateX: -16 }, { translateY: -16 }],
  },
  thumbTitle: {
    position: 'absolute',
    bottom: 8,
    left: 8,
    right: 8,
    color: '#fff',
    fontSize: 11,
    fontWeight: '600',
    textAlign: 'center',
  },
  closeBtn: {
    position: 'absolute',
    left: 16,
    zIndex: 100,
    backgroundColor: 'rgba(0,0,0,0.6)',
    borderRadius: 20,
    padding: 8,
  },
});

import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
  StyleSheet,
  View,
  Text,
  FlatList,
  SectionList,
  TouchableOpacity,
  ActivityIndicator,
  RefreshControl,
  Dimensions,
  Platform,
  I18nManager,
  ScrollView,
  Modal,
  ImageBackground,
} from 'react-native';
import { StatusBar } from 'expo-status-bar';
import { SafeAreaView, useSafeAreaInsets } from 'react-native-safe-area-context';
import { router, useFocusEffect } from 'expo-router';
import { Image } from 'expo-image';
import { Ionicons } from '@expo/vector-icons';
import { LinearGradient } from 'expo-linear-gradient';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import api from '@/services/api';
import { useAuthStore } from '@/store/authStore';
import { useTheme } from '@/context/ThemeContext';
import { useAppTranslation, useLanguage } from '@/context/LanguageContext';
import { Colors } from '@/constants/Colors';
import { CarBrands, MotorcycleBrands } from '@/constants/CarData';
import StoriesRail, { StoryUser } from '@/components/stories/StoriesRail';
import AddStoryModal from '@/components/stories/AddStoryModal';
import StoryViewer from '@/components/stories/StoryViewer';
import AdsBanner from '@/components/ads/AdsBanner';
import LuckWinnerBanner from '@/components/luck/LuckWinnerBanner';

const { width, height } = Dimensions.get('window');
const CARD_WIDTH = (width - 40) / 2;

type FilterType = 'ALL' | 'CAR' | 'PLATE' | 'PART' | 'MOTORCYCLE';

type SafeModelItem = {
  key: string;
  label: string;
  valueEn: string;
  valueAr: string;
};

type VehicleBrand = (typeof CarBrands)[number];

const HOME_CAR_BRANDS = CarBrands.filter((brand) => brand.id !== 'all');
const HOME_MOTORCYCLE_BRANDS = MotorcycleBrands.filter((brand) => brand.id !== 'all');

// ============================================
// UTILITY: Convert any value to a safe string
// ============================================
function safeString(value: unknown, fallback: string = ''): string {
  if (typeof value === 'string') return value;
  if (typeof value === 'number') return String(value);
  if (value === null || value === undefined) return fallback;
  if (typeof value === 'object') {
    const obj = value as Record<string, unknown>;
    if (typeof obj.ar === 'string') return obj.ar;
    if (typeof obj.en === 'string') return obj.en;
    return fallback;
  }
  return fallback;
}

// ============================================
// UTILITY: Generate safe unique keys for FlatList
// ============================================
function getKey(value: unknown, index: number, prefix: string = 'item'): string {
  const str = safeString(value);
  if (str) {
    return `${prefix}-${str}-${index}`;
  }
  return `${prefix}-${index}`;
}

// ============================================
// BUILD MODEL ITEMS
// ============================================
function buildSafeModelItems(
  brand: { models?: unknown[] } | null | undefined,
  language: 'ar' | 'en',
  t: (key: string, options?: Record<string, unknown>) => string,
): SafeModelItem[] {
  const result: SafeModelItem[] = [];
  result.push({
    key: 'safe-model-all',
    label: t('search.categoryAll'),
    valueEn: '__ALL__',
    valueAr: '__ALL__',
  });
  
  const rawModels = Array.isArray(brand?.models) ? brand.models : [];
  
  for (let i = 0; i < rawModels.length; i++) {
    const model = rawModels[i];
    let labelStr: string;
    let enStr: string;
    let arStr: string;
    
    if (typeof model === 'string') {
      labelStr = model;
      enStr = model;
      arStr = model;
    } else if (model && typeof model === 'object') {
      const modelObj = model as Record<string, unknown>;
      enStr = typeof modelObj.en === 'string' ? modelObj.en : '';
      arStr = typeof modelObj.ar === 'string' ? modelObj.ar : '';
      labelStr = language === 'ar' ? (arStr || enStr) : (enStr || arStr);
      labelStr = labelStr || t('search.modelFallback', { index: i + 1 });
      if (!enStr) enStr = arStr || `model_${i}`;
      if (!arStr) arStr = enStr;
    } else {
      labelStr = t('search.modelFallback', { index: i + 1 });
      enStr = `unknown_model_${i}`;
      arStr = labelStr;
    }
    
    result.push({
      key: `safe-model-${i}-${enStr.replace(/\s+/g, '_')}`,
      label: labelStr,
      valueEn: enStr,
      valueAr: arStr,
    });
  }
  
  result.push({
    key: 'safe-model-other',
    label: t('common.other'),
    valueEn: '__OTHER__',
    valueAr: '__OTHER__',
  });
  
  return result;
}

