const FilterHeader = React.memo(({ selectedFilter, onSelect, theme, options, isRTL }: { selectedFilter: any, onSelect: any, theme: any, options: { label: string; value: FilterType; image: any }[], isRTL: boolean }) => {
  const scrollRef = useRef<any>(null);



  return (
    <View style={[styles.filterContainer, { backgroundColor: theme.surface }]}>
        <ScrollView 
          ref={scrollRef}
          horizontal 
          showsHorizontalScrollIndicator={false}
          contentContainerStyle={[
            styles.filterScroll,
            { flexDirection: 'row' },
          ]}
        >
          {options.map((option) => {
            const isActive = selectedFilter === option.value;
            return (
              <TouchableOpacity
                key={option.value}
                style={[styles.categoryCard, isActive && styles.categoryCardActive]}
                onPress={() => onSelect(option.value)}
                activeOpacity={0.8}
              >
                <Image
                  source={typeof option.image === 'string' ? { uri: option.image } : option.image}
                  style={styles.categoryImage}
                  contentFit="cover"
                  pointerEvents="none"
                />
                <View style={[styles.categoryOverlay, isActive && { backgroundColor: 'rgba(212, 175, 55, 0.4)' }]} pointerEvents="none" />
                
                <Text style={styles.categoryText} pointerEvents="none">
                  {option.label}
                </Text>
              </TouchableOpacity>
            );
          })}
        </ScrollView>
      </View>
  );
});

export default function HomeScreen() {
  const insets = useSafeAreaInsets();
  const queryClient = useQueryClient();
  const { t } = useAppTranslation();
  const { language, isRTL } = useLanguage();

  // Query key — changes trigger a new fetch (React Query caches by key)
  const [queryFilter, setQueryFilter] = useState<FilterType>('ALL');
  const [queryParams, setQueryParams] = useState<Record<string, any>>({});

  const [refreshing, setRefreshing] = useState(false);
  const [selectedFilter, setSelectedFilter] = useState<FilterType>('ALL');
  // Store previous filter to revert on cancel
  const [previousFilter, setPreviousFilter] = useState<FilterType>('ALL');
  const [activeParams, setActiveParams] = useState<any>({});
  
  // Filter Modal States
  const [modalVisible, setModalVisible] = useState(false);
  const [filterStep, setFilterStep] = useState<'BRAND' | 'MODEL' | 'MOTO_BRAND' | 'PLATE_TYPE'>('BRAND');
  const [selectedBrand, setSelectedBrand] = useState<VehicleBrand | null>(null);
  const [selectedMotoBrand, setSelectedMotoBrand] = useState<VehicleBrand | null>(null);
  
  // Stories State
  const [addStoryVisible, setAddStoryVisible] = useState(false);
  const [viewerVisible, setViewerVisible] = useState(false);
  const [viewerStories, setViewerStories] = useState<StoryUser[]>([]);
  const [viewerInitialIndex, setViewerInitialIndex] = useState(0);
  const [viewerInitialUserId, setViewerInitialUserId] = useState<string | undefined>(undefined);
  const [storiesRefreshTrigger, setStoriesRefreshTrigger] = useState(0);
  const [unreadCount, setUnreadCount] = useState(0);
  const [luckWinner, setLuckWinner] = useState<{ code: string; userName: string; drawnAt: string } | null>(null);

  const { isDark } = useTheme();
  const { isAuthenticated } = useAuthStore();
  const filterOptions = getFilterOptions(t as any);

  // ─── React Query: cached listings fetch ──────────────────────────────────
  const { data: listings = [], isLoading: loading, refetch } = useQuery<any[]>({
    queryKey: ['listings', queryFilter, queryParams],
    queryFn: async () => {
      const params: any = { status: 'APPROVED', limit: 30, ...queryParams };
      Object.keys(params).forEach((k) => {
        if (params[k] === undefined || params[k] === null || params[k] === '') delete params[k];
      });
      if (queryFilter !== 'ALL') params.type = queryFilter;
      const response = await api.get('/listings', { params });
      const payload = response.data?.data ?? response.data;
      return Array.isArray(payload) ? payload : (payload?.items ?? []);
    },
  });

  // filteredListings = listings (server already filters by type/params)
  const filteredListings = listings;

  useFocusEffect(
    useCallback(() => {
      if (isAuthenticated) {
        api
          .get('/notifications/unread-count')
          .then((res) => {
            const count = res.data?.unreadCount ?? res.data?.data?.unreadCount ?? 0;
            setUnreadCount(count);
          })
          .catch((err) => console.log('Error fetching notification count:', err));
      } else {
        setUnreadCount(0);
      }
    }, [isAuthenticated])
  );

  // Fetch luck winner for banner
  useEffect(() => {
    api.get('/luck/status')
      .then((res) => {
        const data = res.data?.data ?? res.data;
        if (data?.winner) setLuckWinner(data.winner);
      })
      .catch(() => {});
  }, []);

  const sectionData = React.useMemo(() => {
    const data: any[] = [];

    if (selectedFilter === 'ALL') {
      // أحدث العروض — المميزة فقط، إذا لم توجد لا يظهر القسم
      const featured = listings.filter((l: any) => l.isFeatured === true).slice(0, 10);
      if (featured.length > 0) {
        data.push({ type: 'CATEGORY_SECTION', id: 'sec_latest', title: t('home.latestFeatured'), filterType: null, items: featured });
      }
      // قسم لكل فئة
      const categories = [
        { key: 'CAR',        title: t('search.categoryCars'),        filterType: 'CAR'        as FilterType },
        { key: 'MOTORCYCLE', title: t('search.categoryMotorcycles'), filterType: 'MOTORCYCLE' as FilterType },
        { key: 'PLATE',      title: t('search.categoryPlates'),      filterType: 'PLATE'      as FilterType },
        { key: 'PART',       title: t('search.categoryParts'),       filterType: 'PART'       as FilterType },
      ];
      for (const cat of categories) {
        const items = listings.filter((l: any) => l.type === cat.key).slice(0, 10);
        if (items.length > 0) {
          data.push({ type: 'CATEGORY_SECTION', id: `sec_${cat.key}`, title: cat.title, filterType: cat.filterType, items });
        }
      }
      // بنر إعلاني واحد في النهاية
      data.push({ type: 'AD_BANNER', id: 'ad_banner_end' });
    } else {
      // شبكة عادية للفئة المحددة
      data.push({ type: 'HEADER_TITLE', id: 'section_header_title' });
      let adCount = 0;
      for (let i = 0; i < filteredListings.length; i += 2) {
        const rowIndex = i / 2;
        if (rowIndex > 0 && rowIndex % 5 === 0 && adCount < 3) {
          data.push({ type: 'AD_BANNER', id: `ad_banner_${rowIndex}` });
          adCount++;
        }
        data.push({
          type: 'ROW',
          id: `row_${i}`,
          items: filteredListings.slice(i, i + 6)
        });
      }
    }

    return [{ data }];
  }, [filteredListings, listings, selectedFilter, t]);

  const theme = {
    background: isDark ? '#0A0B14' : '#F2F5FC',
    surface: isDark ? '#111C32' : '#FFFFFF',
    border: isDark ? '#1E2D4A' : '#EEF2FA',
    text: isDark ? '#F0F4FC' : '#0A0B14',
    subText: isDark ? '#8899BB' : '#475569',
    muted: isDark ? '#4A5568' : '#9BA3B2',
    primary: Colors.primary,
  };

  const fetchListings = (typeOverride?: FilterType, extraParams: any = null) => {
    const type = typeOverride !== undefined ? typeOverride : selectedFilter;

    let newParams: Record<string, any> = {};
    if (extraParams) {
      // Remove empty values
      Object.keys(extraParams).forEach((k) => {
        if (extraParams[k] !== undefined && extraParams[k] !== null && extraParams[k] !== '') {
          newParams[k] = extraParams[k];
        }
      });
      setActiveParams(newParams);
    } else if (typeOverride) {
      setActiveParams({});
    }

    setQueryFilter(type);
    setQueryParams(newParams);
  };

  const toText = safeString;
  const getLocalizedText = safeString;
  const getListingTitle = (item: any) => safeString(item?.title, '');
  const getListingCity = (item: any) => safeString(item?.city, t('common.bahrain'));
  const getBrandLabel = (brand: any) => language === 'ar' ? (brand?.nameAr || brand?.name || '') : (brand?.name || brand?.nameAr || '');

  const handleFilterChange = (filter: FilterType) => {
    setPreviousFilter(selectedFilter);
    setSelectedFilter(filter);

    setModalVisible(false);
    setSelectedBrand(null);
    setSelectedMotoBrand(null);
    setFilterStep('BRAND');

    fetchListings(filter);
  };

  const closeModal = () => {
    setModalVisible(false);
    
    // If we have PARTIAL selection (e.g. brand selected but model cancelled), process it
    if ((selectedFilter === 'CAR' || selectedFilter === 'MOTORCYCLE') && selectedBrand) {
       const makeName = selectedBrand.nameAr || selectedBrand.name;
       fetchListings(selectedFilter, { make: makeName });
    } 
     else if (selectedFilter === 'MOTORCYCLE' && selectedMotoBrand) {
       const makeName = selectedMotoBrand.nameAr || selectedMotoBrand.name;
       fetchListings('MOTORCYCLE', { make: makeName });
     }
    // If we have selected a PLATE type but not fully committed via handlePlateTypeSelect...
    // Actually handlePlateTypeSelect closes the modal itself. 
    // So if we are here, we likely cancelled the plate type selection.
    
    // If we have NO selection (just opened modal and closed immediately), revert to previous filter
    else if (!selectedBrand && !selectedMotoBrand) {
        setSelectedFilter(previousFilter);
        // Do NOT fetch. Just revert UI state.
    }
    
    setSelectedBrand(null);
    setSelectedMotoBrand(null);
    setFilterStep('BRAND');
  };

  const handleBrandSelect = (brand: any) => {
    setSelectedBrand(brand);
    // Don't fetch here, just move to next step
    setFilterStep('MODEL');
  };

  const handleMotoBrandSelect = (brand: any) => {
    setSelectedMotoBrand(brand);
    // For motorcycles, we don't have models yet, so fetch directly
    const makeName = brand.nameAr || brand.name;
    fetchListings('MOTORCYCLE', { make: makeName, model: undefined });
    setModalVisible(false); // Directly close
  };

  const handlePlateTypeSelect = (plateType: string) => {
    if (plateType === 'ALL') {
       fetchListings('PLATE', { plateType: undefined });
    } else {
       fetchListings('PLATE', { plateType: plateType });
    }
    setModalVisible(false); // Directly close
  };

  const handleModelSelect = (modelItem: SafeModelItem) => {
    const modelEn = modelItem.valueEn;
    const modelAr = modelItem.valueAr;
    setModalVisible(false); // Close first
    
    // NOW fetch
    const brandName = selectedBrand?.nameAr || selectedBrand?.name;
    if (modelEn === '__ALL__' || modelEn === '__OTHER__') {
      fetchListings(selectedFilter, { make: brandName, model: undefined }); // Use current context filter
    } else {
      fetchListings(selectedFilter, { make: brandName, model: modelAr }); // Use current context filter
    }
    
    // Reset state after selection
    setSelectedBrand(null);
    setFilterStep('BRAND');
  };

  const onRefresh = () => {
    setRefreshing(true);
    setStoriesRefreshTrigger(prev => prev + 1);
    refetch().finally(() => setRefreshing(false));
  };

  const handleAddStory = () => setAddStoryVisible(true);

  const handleStoryPress = (index: number, stories: StoryUser[], userId?: string) => {
    setViewerStories(stories);
    setViewerInitialIndex(index);
    setViewerInitialUserId(userId);
    setViewerVisible(true);
  };

  const handleStorySuccess = () => {
    setAddStoryVisible(false);
    setStoriesRefreshTrigger(prev => prev + 1);
  };

  const getImageUris = (item: any): string[] => {
    const media = item?.media;
    if (Array.isArray(media) && media.length > 0) {
      // Filter to IMAGE type only — video URLs cannot be rendered by expo-image
      const imageMedia = media.filter((m: any) => m?.type === 'IMAGE' || m?.type === 'image');
      if (imageMedia.length > 0) {
        return imageMedia.map((m: any) => m?.url).filter(Boolean) as string[];
      }
      // Fallback: if no media has a type field, return all that have urls
      return media.map((m: any) => m?.url).filter(Boolean) as string[];
    }
    const images = item?.images;
    if (Array.isArray(images) && images.length > 0) {
      return images.map((img: any) => {
        if (typeof img === 'string') return img;
        if (img?.url) return img.url;
        return null;
      }).filter(Boolean) as string[];
    }
    return [];
  };

  const getImageUri = (item: any) => {
    const uris = getImageUris(item);
    return uris.length > 0 ? uris[0] : null;
  };

  // ============================================
  // NEW LUXURY CARD DESIGN
  // ============================================
  const renderListingCard = ({ item }: { item: any }) => {
    const imageUris = getImageUris(item);
    const imageUri = imageUris.length > 0 ? imageUris[0] : null;
    const typeAccent =
      item.type === 'MOTORCYCLE' ? '#8B5CF6' :
      item.type === 'PLATE'      ? '#059669' :
      item.type === 'PART'       ? '#F59E0B' :
      '#3B82F6';
    const typeLabel =
      item.type === 'PLATE' ? t('listing.types.plate') :
      item.type === 'MOTORCYCLE' ? t('listing.types.motorcycle') :
      item.type === 'PART' ? t('listing.types.part') : t('listing.types.car');

    return (
      <TouchableOpacity
        style={[styles.card, { backgroundColor: theme.surface }]}
        onPress={() =>
          router.push({
            pathname: '/listing/[id]',
            params: { id: String(item.id), backLink: '/(tabs)/index' },
          })
        }
        activeOpacity={0.88}
      >
        {/* Colored top accent bar */}
        <View style={{ height: 3, backgroundColor: typeAccent }} pointerEvents="none" />

        <View style={styles.imageContainer} pointerEvents="none">
          {imageUri ? (
            <Image
              source={{ uri: imageUri }}
              style={styles.cardImage}
              contentFit="cover"
              cachePolicy="memory-disk"
              transition={200}
              pointerEvents="none"
            />
          ) : (
            <View style={[styles.cardImage, styles.noImage, { backgroundColor: typeAccent + '18' }]}>
              <Ionicons name="car-outline" size={36} color={typeAccent} />
            </View>
          )}
          {/* Image count badge */}
          {imageUris.length > 1 && (
            <View style={styles.imageCountBadge}>
              <Ionicons name="images-outline" size={10} color="#FFF" />
              <Text style={styles.imageCountText}>{imageUris.length}</Text>
            </View>
          )}
          {/* Price overlay — bottom fade */}
          <LinearGradient
            colors={['transparent', 'rgba(0,0,0,0.72)']}
            start={{ x: 0, y: 0 }}
            end={{ x: 0, y: 1 }}
            style={[styles.priceOverlay, { alignItems: isRTL ? 'flex-end' : 'flex-start' }]}
          >
            <Text style={[styles.priceText, { textAlign: 'auto'}]}>
              {toText(
                typeof item.price === 'number'
                  ? item.price.toLocaleString()
                  : Number(item.price || 0).toLocaleString()
              )} {t('common.bhd')}
            </Text>
          </LinearGradient>

          {/* Type badge — colored pill */}
          <View style={[styles.typeBadge, { backgroundColor: typeAccent }]}>
            <Text style={styles.typeText}>{typeLabel}</Text>
          </View>
        </View>

        <View style={[styles.cardContent, { alignItems: isRTL ? 'flex-end' : 'flex-start' }]} pointerEvents="none">
          <Text style={[styles.cardTitle, { color: theme.text, textAlign: 'auto'}]} numberOfLines={1}>
            {toText(getListingTitle(item))}
          </Text>

          <View style={[styles.separator, { backgroundColor: theme.border }]} />

          <View style={[styles.cardFooter, { flexDirection: 'row' }]}>
            <View style={[styles.metaRow, { flexDirection: 'row' }]}>
              <Ionicons name="location-sharp" size={11} color={typeAccent} />
              <Text style={[styles.metaText, { color: theme.subText, textAlign: 'auto'}]}>{toText(getListingCity(item), t('common.bahrain'))}</Text>
            </View>
            <View style={[styles.metaRow, { flexDirection: 'row' }]}>
              <Ionicons name="time-outline" size={11} color={theme.muted} />
              <Text style={[styles.metaText, { color: theme.muted, textAlign: 'auto'}]}>{toText(formatTimeAgo(item.postedAt || item.createdAt, language, t))}</Text>
            </View>
          </View>
        </View>
      </TouchableOpacity>
    );
  };

  if (loading) {
    return (
      <SafeAreaView edges={['left', 'right', 'bottom']} style={[styles.loadingContainer, { backgroundColor: theme.background }]}>
        <ActivityIndicator size="large" color={Colors.primary} />
      </SafeAreaView>
    );
  }

  return (
    <View style={{ flex: 1, backgroundColor: theme.background }}>
      <StatusBar style={isDark ? "light" : "dark"} backgroundColor={theme.background} />
      {/* Watermark Background */}
      <View style={StyleSheet.absoluteFill} pointerEvents="none">
         <Image 
           source={require('@/assets/images/logo.png')} 
           style={styles.watermark}
           contentFit="contain"
         />
      </View>

      <SafeAreaView style={{ flex: 1 }} edges={['left', 'right', 'bottom']}>
        {/* ── Header: dark navy (light) / gold (dark) ── */}
        <LinearGradient
          colors={['#0E1830', '#162444']}
          start={{ x: 0, y: 0 }}
          end={{ x: 1, y: 1 }}
          style={[styles.logoContainer, { width: '100%', alignSelf: 'stretch' }]}
        >
          <View style={styles.headerTopRow}>
            {/* Logo absolutely centered */}
            <View style={{ position: 'absolute', left: 0, right: 0, alignItems: 'center', zIndex: 0 }} pointerEvents="none">
              <Image
                source={require('@/assets/images/logo.png')}
                style={styles.logo}
                contentFit="contain"
              />
            </View>

            {/* Left side: Notification bell + Search */}
            <View style={{ flexDirection: 'row', gap: 8, zIndex: 1 }}>
              <TouchableOpacity
                onPress={() => router.push('/notifications')}
                style={[styles.iconButton, { backgroundColor: 'rgba(255,255,255,0.1)' }]}
              >
                <Ionicons name="notifications" size={22} color='#D4AF37' />
                {unreadCount > 0 && (
                  <View style={styles.badgeContainer}>
                    <Text style={styles.badgeText}>
                      {unreadCount > 99 ? '99+' : unreadCount}
                    </Text>
                  </View>
                )}
              </TouchableOpacity>

              {/* Search */}
              <TouchableOpacity
                onPress={() => router.push('/search')}
                style={[styles.iconButton, { backgroundColor: 'rgba(255,255,255,0.1)' }]}
              >
                <Ionicons name="search" size={22} color='#D4AF37' />
              </TouchableOpacity>
            </View>

            {/* Favorites heart */}
            <TouchableOpacity
              onPress={() => router.push({ pathname: '/favorites', params: { source: 'home' } })}
              style={[styles.iconButton, { backgroundColor: 'rgba(255,255,255,0.1)' }]}
            >
              <Ionicons name="heart" size={22} color='#D4AF37' />
            </TouchableOpacity>
          </View>
        </LinearGradient>

        {/* Stories Rail */}
        <StoriesRail
          onAddStory={handleAddStory}
          onPressStory={handleStoryPress}
          refreshTrigger={storiesRefreshTrigger}
        />

        {/* FilterHeader خارج SectionList */}
        <View style={{ backgroundColor: theme.surface, zIndex: 20, elevation: 6 }}>
          <FilterHeader 
            selectedFilter={selectedFilter} 
            onSelect={handleFilterChange} 
            theme={theme} 
            options={filterOptions}
            isRTL={isRTL}
          />
        </View>

        <SectionList
          sections={sectionData}
          stickySectionHeadersEnabled={false}
          removeClippedSubviews={false}
          keyExtractor={(item) => item.id}
          showsVerticalScrollIndicator={false}
          refreshControl={
            <RefreshControl refreshing={refreshing} onRefresh={onRefresh} tintColor={Colors.primary} />
          }
          contentContainerStyle={[
            styles.listContainer, 
            { 
              paddingHorizontal: 0,
              paddingBottom: Math.max(160, 32 + Math.max(insets.bottom, 16)),
            }
          ]}
          ListHeaderComponent={luckWinner ? <LuckWinnerBanner winner={luckWinner} /> : undefined}
          renderSectionHeader={undefined}
          renderItem={({ item }) => {
            if (item.type === 'HEADER_TITLE') {
              return (
                <View style={{ width: '100%', paddingHorizontal: 16, paddingVertical: 16, flexDirection: 'row' }}>
                  <View>
                    <Text style={{ fontSize: 20, fontWeight: '800', textAlign: 'auto', color: theme.text}}>{t('home.latestOffers')}</Text>
                    <View style={{ height: 3, width: 40, backgroundColor: Colors.primary, borderRadius: 2, marginTop: 4 }} />
                  </View>
                </View>
              );
            }

            if (item.type === 'CATEGORY_SECTION') {
              return (
                <View style={{ marginBottom: 4 }}>
                  <View style={{
                    flexDirection: 'row',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    paddingHorizontal: 16,
                    paddingTop: 20,
                    paddingBottom: 12,
                  }}>
                    <View>
                      <Text style={{ fontSize: 18, fontWeight: '800', textAlign: 'auto', color: theme.text}}>{item.title}</Text>
                      <View style={{ height: 3, width: 36, backgroundColor: Colors.primary, borderRadius: 2, marginTop: 4 }} />
                    </View>
                    {item.filterType && (
                      <TouchableOpacity onPress={() => handleFilterChange(item.filterType)}>
                        <Text style={{ color: Colors.primary, fontSize: 13, fontWeight: '600', textAlign: 'auto'}}>{t('home.showAll')}</Text>
                      </TouchableOpacity>
                    )}
                  </View>
                  <ScrollView
                    horizontal
                    showsHorizontalScrollIndicator={false}
                    contentContainerStyle={{ paddingHorizontal: 16, gap: 12 }}
                  >
                    {item.items.map((listing: any) => (
                      <View key={listing.id}>
                        {renderListingCard({ item: listing })}
                      </View>
                    ))}
                  </ScrollView>
                </View>
              );
            }

            if (item.type === 'AD_BANNER') {
              return <AdsBanner />;
            }

            if (item.type === 'ROW') {
              return (
                <View style={[styles.row, { paddingHorizontal: 16 }]}> 
                    {item.items && item.items[0] && renderListingCard({ item: item.items[0] })}
                    {item.items && item.items[1] ? (
                      renderListingCard({ item: item.items[1] })
                    ) : (
                      <View style={{ width: CARD_WIDTH }} />
                    )}
                </View>
              );
            }
            return null;
          }}
          ListEmptyComponent={
            !loading && filteredListings.length === 0 ? (
              <View style={styles.emptyContainer}>
                <Ionicons name="car-sport-outline" size={60} color="#e5e5e5" />
                <Text style={[styles.emptyText, { color: theme.muted, marginTop: 10 }]}>{t('home.noMatchingListings')}</Text>
              </View>
            ) : null
          }
        />

        <Modal
          animationType="slide"
          transparent={true}
          visible={modalVisible}
          onRequestClose={closeModal}
        >
          <View style={styles.modalOverlay}>
            <View style={[styles.modalContent, { backgroundColor: theme.surface }]}> 
              <View style={[styles.modalHeader, { flexDirection: 'row' }]}>
                <Text style={[styles.modalTitle, { color: theme.text, textAlign: 'auto'}]}> 
                  {filterStep === 'BRAND' ? t('home.chooseBrand') : 
                  filterStep === 'MOTO_BRAND' ? t('home.chooseManufacturer') :
                  filterStep === 'PLATE_TYPE' ? t('home.choosePlateType') :
                  t('home.chooseModel')}
                </Text>
                <TouchableOpacity onPress={closeModal} style={styles.closeButton}>
                  <Ionicons name="close" size={24} color={theme.text} />
                </TouchableOpacity>
              </View>
              
              {filterStep === 'BRAND' && (
                <FlatList
                  data={HOME_CAR_BRANDS}
                  keyExtractor={(item, index) => getKey(item?.id ?? item?.name, index, 'brand')}
                  numColumns={3}
                  contentContainerStyle={styles.brandGrid}
                  renderItem={({ item }) => (
                    <TouchableOpacity 
                      style={[styles.brandItem, { borderColor: theme.border }]} 
                      onPress={() => handleBrandSelect(item)}
                    >
                      <View style={styles.brandLogoContainer}>
                        <Image 
                          source={{ uri: item.logo }} 
                          style={styles.brandLogo} 
                          contentFit="contain"
                          transition={200}
                        />
                      </View>
                      <Text style={[styles.brandName, { color: theme.text }]}>{getBrandLabel(item)}</Text>
                    </TouchableOpacity>
                  )}
                />
              )}

              {filterStep === 'MOTO_BRAND' && (
                <FlatList
                  data={HOME_MOTORCYCLE_BRANDS}
                  keyExtractor={(item) => item.id}
                  numColumns={3}
                  contentContainerStyle={styles.brandGrid}
                  renderItem={({ item }) => (
                    <TouchableOpacity 
                      style={[styles.brandItem, { borderColor: theme.border }]} 
                      onPress={() => handleMotoBrandSelect(item)}
                    >
                      <View style={styles.brandLogoContainer}>
                        <Image 
                          source={{ uri: item.logo }} 
                          style={styles.brandLogo} 
                          contentFit="contain"
                          transition={200}
                        />
                      </View>
                      <Text style={[styles.brandName, { color: theme.text }]}>{getBrandLabel(item)}</Text>
                    </TouchableOpacity>
                  )}
                />
              )}

              {filterStep === 'PLATE_TYPE' && (
                <View style={styles.modelList}>
                  {[
                    { id: 'ALL', label: t('search.categoryAll') },
                    { id: 'PRIVATE', label: t('home.platePrivate') },
                    { id: 'TRANSPORT', label: t('home.plateTransport') },
                    { id: 'MOTORCYCLE', label: t('home.plateMotorcycle') }
                  ].map((pt) => (
                    <TouchableOpacity 
                        key={pt.id}
                        style={[styles.modelItem, { borderBottomColor: theme.border, flexDirection: 'row' }]} 
                        onPress={() => handlePlateTypeSelect(pt.id)}
                      >
                        <Text style={[styles.modelName, { color: theme.text, textAlign: 'auto'}]}>{pt.label}</Text>
                        <Ionicons name={isRTL ? 'chevron-back' : 'chevron-forward'} size={20} color={theme.muted} />
                      </TouchableOpacity>
                  ))}
                </View>
              )}

              {filterStep === 'MODEL' && (
                <View style={{ flex: 1 }}>
                  <TouchableOpacity onPress={() => setFilterStep('BRAND')} style={[styles.backButton, { flexDirection: 'row' }]}>
                  <Ionicons name={isRTL ? 'arrow-forward' : 'arrow-back'} size={20} color={theme.primary} />
                  <Text style={[styles.backText, { color: theme.primary, textAlign: 'auto'}]}>{t('home.backToBrands')}</Text>
                  </TouchableOpacity>
                  <FlatList<SafeModelItem>
                    data={buildSafeModelItems(selectedBrand, language, t as any)}
                    keyExtractor={(item: SafeModelItem) => item.key}
                    contentContainerStyle={styles.modelList}
                    renderItem={({ item }: { item: SafeModelItem }) => (
                      <TouchableOpacity 
                        style={[styles.modelItem, { borderBottomColor: theme.border, flexDirection: 'row' }]} 
                        onPress={() => handleModelSelect(item)}
                      >
                        <Text style={[styles.modelName, { color: theme.text, textAlign: 'auto'}]}> 
                          {item.label}
                        </Text>
                        <Ionicons name={isRTL ? 'chevron-back' : 'chevron-forward'} size={20} color={theme.muted} />
                      </TouchableOpacity>
                    )}
                  />
                </View>
              )}
            </View>
          </View>
        </Modal>

        <AddStoryModal
          visible={addStoryVisible}
          onClose={() => setAddStoryVisible(false)}
          onSuccess={handleStorySuccess}
        />

        <StoryViewer
          visible={viewerVisible}
          storyUsers={viewerStories}
          initialUserIndex={viewerInitialIndex}
          initialUserId={viewerInitialUserId}
          onClose={() => setViewerVisible(false)}
        />

      </SafeAreaView>
    </View>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { View, Text, StyleSheet, FlatList, TouchableOpacity, Alert, RefreshControl, ActivityIndicator, Platform } from 'react-native';
import { LinearGradient } from 'expo-linear-gradient';
import { SafeAreaView } from 'react-native-safe-area-context';
import { router, useFocusEffect } from 'expo-router';
import { Ionicons } from '@expo/vector-icons';
import { Image } from 'expo-image';
import { Colors } from '@/constants/Colors';
import { useAuthStore } from '@/store/authStore';
import api from '@/services/api';
import { useAppTranslation } from '@/context/LanguageContext';
import { useTheme } from '@/context/ThemeContext';
import { PageHeader } from '@/components/ui/page-header';

interface Listing {
  id: string;
  type: 'CAR' | 'PLATE' | 'PART';
  status: 'DRAFT' | 'PENDING_REVIEW' | 'APPROVED' | 'SOLD' | 'REJECTED' | 'ARCHIVED';
  title: string;
  price: number | string; // Can be Decimal string from backend
  currency: string;
  locationGovernorate?: string;
  viewsCount: number;
  favoritesCount: number;
  postedAt?: string;
  media: Array<{
    id: string;
    url: string;
    type: string;
  }>;
  rejectionReason?: string;
}

export default function MyListingsScreen() {
  const { isAuthenticated } = useAuthStore();
  const { isDark } = useTheme();
  const { t } = useAppTranslation();
  const [listings, setListings] = useState<Listing[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [filter, setFilter] = useState<'ALL' | 'ACTIVE' | 'PENDING_REVIEW' | 'SOLD'>('ALL');

  const theme = {
    background: isDark ? '#0B0F1E' : '#F2F5FC',
    surface:    isDark ? '#111827' : '#FFFFFF',
    card:       isDark ? '#111827' : '#FFFFFF',
    border:     isDark ? 'rgba(255,255,255,0.06)' : 'rgba(0,0,0,0.06)',
    text:       isDark ? '#F8FAFC' : '#0A0B14',
    textMuted:  isDark ? '#64748B' : '#94A3B8',
    subText:    isDark ? '#CBD5E1' : '#6B7280',
    primary: Colors.primary,
  };

  const dirText = { textAlign: 'auto' as const};
  const rowDirection = { flexDirection: 'row' as const };

  const statusLabels: Record<string, { label: string; color: string; bg: string }> = {
    DRAFT: { label: t('myListings.statusDraft'), color: '#64748B', bg: '#F1F5F9' },
    PENDING_REVIEW: { label: t('myListings.statusPendingReview'), color: '#F59E0B', bg: '#FEF3C7' },
    ACTIVE: { label: t('myListings.statusActive'), color: '#10B981', bg: '#D1FAE5' },
    SOLD: { label: t('myListings.statusSold'), color: '#6366F1', bg: '#E0E7FF' },
    REJECTED: { label: t('myListings.statusRejected'), color: '#EF4444', bg: '#FEE2E2' },
    EXPIRED: { label: t('myListings.statusExpired'), color: '#9CA3AF', bg: '#F3F4F6' },
  };

  const getDisplayStatus = (status: Listing['status']) => {
    if (status === 'APPROVED') return 'ACTIVE';
    if (status === 'ARCHIVED') return 'EXPIRED';
    return status;
  };

  const fetchListings = async (showRefreshing = false) => {
    if (showRefreshing) {
      setIsRefreshing(true);
    } else {
      setIsLoading(true);
    }

    try {
      const response = await api.get('/listings/my/all');
      const items = response.data?.data || [];
      setListings(items.filter((item: Listing) => item.status !== 'ARCHIVED'));
    } catch (error: any) {
      console.error('Failed to fetch listings:', error);
      if (error.response?.status !== 401) {
        Alert.alert(t('common.error'), t('myListings.loadFailed'));
      }
    } finally {
      setIsLoading(false);
      setIsRefreshing(false);
    }
  };

  useFocusEffect(
    useCallback(() => {
      if (isAuthenticated) {
        fetchListings();
      }
    }, [isAuthenticated])
  );

  const handleDelete = async (listingId: string) => {
    Alert.alert(
      t('myListings.deleteTitle'),
      t('myListings.deleteMessage'),
      [
        { text: t('common.cancel'), style: 'cancel' },
        {
          text: t('myListings.deleteConfirm'),
          style: 'destructive',
          onPress: async () => {
            try {
              await api.delete(`/listings/${listingId}`);
              setListings(listings.filter(l => l.id !== listingId));
              fetchListings(true);
              Alert.alert(t('common.success'), t('myListings.deleteSuccess'));
            } catch (error: any) {
              Alert.alert(t('common.error'), t('myListings.deleteFailed'));
            }
          },
        },
      ]
    );
  };

  const handleEdit = (listing: Listing) => {
    router.push({
      pathname: '/add-listing/[id]',
      params: { id: listing.id, type: listing.type, mode: 'edit' },
    });
  };

  const handleMarkAsSold = async (listingId: string) => {
    Alert.alert(
      t('myListings.soldTitle'),
      t('myListings.soldMessage'),
      [
        { text: t('common.cancel'), style: 'cancel' },
        {
          text: t('myListings.confirmYes'),
          onPress: async () => {
            try {
              await api.post(`/listings/${listingId}/mark-sold`);
              fetchListings();
              Alert.alert(t('common.success'), t('myListings.soldSuccess'));
            } catch (error: any) {
              Alert.alert(t('common.error'), t('myListings.updateFailed'));
            }
          },
        },
      ]
    );
  };

  const filteredListings = listings.filter(listing => {
    if (filter === 'ALL') return true;
    return getDisplayStatus(listing.status) === filter;
  });

  const renderListingCard = ({ item }: { item: Listing }) => {
    const displayStatus = getDisplayStatus(item.status);
    const statusInfo = statusLabels[displayStatus] || statusLabels.DRAFT;
    const thumbnail = (item.media?.find((m: any) => m?.type === 'IMAGE' || m?.type === 'image') ?? item.media?.[0])?.url;
    const canEdit = item.status === 'DRAFT' || item.status === 'REJECTED' || item.status === 'APPROVED';

    const typeAccent =
      (item.type as string) === 'MOTORCYCLE' ? '#8B5CF6' :
      item.type === 'PLATE'                  ? '#059669' :
      item.type === 'PART'                   ? '#F59E0B' :
      '#3B82F6';

    return (
      <TouchableOpacity
        style={[styles.card, { backgroundColor: theme.card }]}
        activeOpacity={0.85}
        onPress={() => {
          if (item.status === 'DRAFT') {
            router.push({ pathname: '/add-listing/[id]', params: { id: item.id, type: item.type, mode: 'edit' } });
          } else {
            router.push({ pathname: '/listing/[id]', params: { id: item.id } });
          }
        }}
      >
        {/* Colored accent bar top */}
        <View style={{ height: 3, backgroundColor: typeAccent, borderTopLeftRadius: 20, borderTopRightRadius: 20 }} />

        <View style={styles.cardContent}>
          <View style={styles.thumbnailWrapper}>
            {thumbnail ? (
              <Image source={{ uri: thumbnail }} style={styles.thumbnail} contentFit="cover" />
            ) : (
              <View style={[styles.thumbnail, styles.thumbnailPlaceholder, { backgroundColor: typeAccent + '18' }]}>
                <Ionicons name="car-outline" size={32} color={typeAccent} />
              </View>
            )}
            <View style={styles.watermarkContainer} pointerEvents="none">
              <Image source={require('@/assets/images/logo.png')} style={styles.watermarkImage} contentFit="contain" />
            </View>
          </View>

          <View style={styles.cardInfo}>
            <View style={[styles.cardHeader, rowDirection]}>
              <Text style={[styles.cardTitle, { color: theme.text }, dirText]} numberOfLines={2}>
                {item.title}
              </Text>
              <View style={[styles.statusBadge, { backgroundColor: statusInfo.bg }]}>
                <Text style={[styles.statusText, { color: statusInfo.color }]}>
                  {statusInfo.label}
                </Text>
              </View>
            </View>

            <Text style={[styles.cardPrice, { color: theme.primary }, dirText]}>
              {item.price 
                ? (typeof item.price === 'number' 
                    ? item.price.toFixed(3) 
                    : (isNaN(parseFloat(item.price)) ? '0.000' : parseFloat(item.price).toFixed(3)))
                : '0.000'} {item.currency || 'BHD'}
            </Text>

            {item.locationGovernorate && (
              <View style={[styles.cardLocation, rowDirection]}>
                <Ionicons name="location-outline" size={14} color={theme.textMuted} />
                <Text style={[styles.cardLocationText, { color: theme.textMuted }, dirText]}>{item.locationGovernorate}</Text>
              </View>
            )}

            {item.status === 'APPROVED' && (
              <View style={[styles.cardStats, rowDirection]}>
                <View style={[styles.stat, rowDirection]}>
                  <Ionicons name="eye-outline" size={16} color={theme.textMuted} />
                  <Text style={[styles.statText, { color: theme.textMuted }, dirText]}>{item.viewsCount}</Text>
                </View>
                <View style={[styles.stat, rowDirection]}>
                  <Ionicons name="heart-outline" size={16} color={theme.textMuted} />
                  <Text style={[styles.statText, { color: theme.textMuted }, dirText]}>{item.favoritesCount}</Text>
                </View>
              </View>
            )}

            {item.status === 'REJECTED' && item.rejectionReason && (
              <View style={[styles.rejectionBox, { backgroundColor: isDark ? '#3b1f1f' : '#FEE2E2' }, rowDirection]}>
                <Ionicons name="alert-circle" size={16} color="#EF4444" />
                <Text style={[styles.rejectionText, dirText]} numberOfLines={2}>
                  {item.rejectionReason}
                </Text>
              </View>
            )}
          </View>
        </View>

        <View style={[styles.cardActions, { borderTopColor: theme.border }, rowDirection]}>
          {canEdit && (
            <TouchableOpacity
              style={[styles.actionButton, rowDirection]}
              onPress={(e: any) => {
                e?.stopPropagation?.();
                handleEdit(item);
              }}
            >
              <Ionicons name="create-outline" size={20} color={Colors.primary} />
              <Text style={[styles.actionButtonText, { color: theme.primary }, dirText]}>
                {item.status === 'DRAFT' ? t('myListings.complete') : t('myListings.edit')}
              </Text>
            </TouchableOpacity>
          )}

          {item.status === 'APPROVED' && (
            <TouchableOpacity
              style={[styles.actionButton, rowDirection]}
              onPress={(e: any) => {
                e?.stopPropagation?.();
                handleMarkAsSold(item.id);
              }}
            >
              <Ionicons name="checkmark-circle-outline" size={20} color="#10B981" />
              <Text style={[styles.actionButtonText, { color: '#10B981' }, dirText]}>{t('myListings.soldAction')}</Text>
            </TouchableOpacity>
          )}

          <TouchableOpacity
            style={[styles.actionButton, rowDirection]}
            onPress={(e: any) => {
              e?.stopPropagation?.();
              handleDelete(item.id);
            }}
          >
            <Ionicons name="trash-outline" size={20} color="#EF4444" />
            <Text style={[styles.actionButtonText, { color: '#EF4444' }, dirText]}>{t('myListings.deleteAction')}</Text>
          </TouchableOpacity>
        </View>
      </TouchableOpacity>
    );
  };

  if (!isAuthenticated) {
    return (
      <SafeAreaView edges={['left', 'right', 'bottom']} style={[styles.container, { backgroundColor: theme.background }]}>
        <View style={styles.emptyContainer}>
          <Ionicons name="lock-closed-outline" size={64} color={theme.textMuted} />
          <Text style={[styles.emptyTitle, { color: theme.text }, dirText]}>{t('myListings.loginRequired')}</Text>
          <Text style={[styles.emptyText, { color: theme.textMuted }, dirText]}>
            {t('myListings.loginRequiredMessage')}
          </Text>
          <TouchableOpacity
            style={styles.loginButton}
            onPress={() => router.push('/(auth)/login')}
          >
            <Text style={styles.loginButtonText}>{t('myListings.loginAction')}</Text>
          </TouchableOpacity>
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView edges={['left', 'right', 'bottom']} style={[styles.container, { backgroundColor: theme.background }]}>
      <PageHeader
        title={t('tabs.myListings')}
        variant="gradient"
        onBack={() => router.replace('/profile')}
        rightSlot={(
          <TouchableOpacity style={styles.addButton} onPress={() => router.push('/(tabs)/add')}>
            <Ionicons name="add-circle" size={28} color="#D4AF37" />
          </TouchableOpacity>
        )}
      />

      <View style={[styles.filterContainer, rowDirection]}>
        {[
          { key: 'ALL', label: t('myListings.allFilter') },
          { key: 'ACTIVE', label: t('myListings.statusActive') },
          { key: 'PENDING_REVIEW', label: t('myListings.statusPendingReview') },
          { key: 'SOLD', label: t('myListings.soldAction') },
        ].map((f) => (
          <TouchableOpacity
            key={f.key}
            style={[styles.filterButton, filter === f.key && styles.filterButtonActive]}
            onPress={() => setFilter(f.key as any)}
          >
            <Text style={[styles.filterButtonText, filter === f.key && styles.filterButtonTextActive]}>
              {f.label}
            </Text>
          </TouchableOpacity>
        ))}
      </View>

      {isLoading ? (
        <View style={styles.loadingContainer}>
          <ActivityIndicator size="large" color={theme.primary} />
        </View>
      ) : filteredListings.length === 0 ? (
        <View style={styles.emptyContainer}>
          <Ionicons name="document-text-outline" size={64} color={theme.textMuted} />
          <Text style={[styles.emptyTitle, { color: theme.text }, dirText]}>{t('myListings.noListings')}</Text>
          <Text style={[styles.emptyText, { color: theme.textMuted }, dirText]}>
            {filter === 'ALL'
              ? t('myListings.noListingsYet')
              : t('myListings.noListingsWithFilter', {
                  status:
                    filter === 'ACTIVE'
                      ? t('myListings.filterActive')
                      : filter === 'PENDING_REVIEW'
                      ? t('myListings.filterPendingReview')
                      : t('myListings.filterSold'),
                })}
          </Text>
          {filter === 'ALL' && (
            <TouchableOpacity
              style={[styles.addNewButton, rowDirection]}
              onPress={() => router.push('/(tabs)/add')}
            >
              <Ionicons name="add" size={20} color="#FFFFFF" />
              <Text style={styles.addNewButtonText}>{t('myListings.addNewListing')}</Text>
            </TouchableOpacity>
          )}
        </View>
      ) : (
        <FlatList
          data={filteredListings}
          renderItem={renderListingCard}
          keyExtractor={(item) => item.id}
          contentContainerStyle={[styles.listContent, { paddingBottom: 120 }]}
          refreshControl={
            <RefreshControl
              refreshing={isRefreshing}
              onRefresh={() => fetchListings(true)}
              colors={[theme.primary]}
            />
          }
        />
      )}
    </SafeAreaView>
  );
}

