                },
                (isCurrent || isSelected) && { borderWidth: 2 },
              ]}
              onPress={() => setSelectedPkg(pkg.id)}
              activeOpacity={0.8}
            >
              {isCurrent && (
                <View style={styles.currentBadge}>
                  <Text style={[styles.currentBadgeText, dirText]}>{t('subscriptions.currentPackage')}</Text>
