                  </Text>
                  <Text style={[styles.pkgPriceSub, { color: mutedColor }, dirText]}>
                    {RLM} / {activeOption.label} {RLM}
                  </Text>
                </View>
              </View>

              {pkg.discountNote && (
                <View style={styles.discountBadge}>
                  <Ionicons name="pricetag" size={12} color="#16A34A" />
