              </View>

              <View style={[styles.pkgFeature, rowDirection]}>
                <Ionicons name="checkmark-circle" size={16} color="#16A34A" />
                <Text style={[styles.pkgFeatureText, { color: mutedColor }, dirText]}>
                  {t('subscriptions.durationDays', { count: pkg.durationDays })}
                </Text>
              </View>

              {/* Duration selector — shown only for selected package */}
              {isSelected && durationOptions.length > 1 && (
                <View style={styles.durationRow}>
                  {durationOptions.map((opt) => (
                    <TouchableOpacity
                      key={opt.key}
                      style={[
                        styles.durationBtn,
                        {
                          backgroundColor:
                            selectedDuration === opt.key
                              ? '#D4AF37'
                              : isDark
                              ? 'rgba(255,255,255,0.08)'
                              : '#F1F5F9',
                          borderColor: selectedDuration === opt.key ? '#D4AF37' : isDark ? 'rgba(255,255,255,0.15)' : '#CBD5E1',
                        },
                      ]}
                      onPress={() => setSelectedDuration(opt.key)}
                    >
                      <Text
                        style={[
                          styles.durationBtnText,
                          { color: selectedDuration === opt.key ? '#0A0B14' : textColor },
                          dirText,
                        ]}
                      >
                        {opt.label}
                      </Text>
                      <Text
                        style={[
                          styles.durationBtnPrice,
                          { color: selectedDuration === opt.key ? '#0A0B14' : mutedColor },
                          dirText,
                        ]}
                      >
                        {opt.price.toFixed(3)} {t('common.bhd')}
                      </Text>
                    </TouchableOpacity>
                  ))}
                </View>
              )}
            </TouchableOpacity>
          );
        })}

        {/* Subscribe button */}
        {selectedPkg && (
          <TouchableOpacity style={styles.subscribeBtn} onPress={() => handleSubscribe(selectedPkg)} disabled={subscribing} activeOpacity={0.85}>
            <LinearGradient
              colors={['#E8C84A', '#D4AF37', '#A8860E']}
              start={{ x: 0, y: 0 }}
              end={{ x: 1, y: 0 }}
              style={styles.subscribeBtnGrad}
            >
              {subscribing ? (
                <ActivityIndicator color="#0A0B14" />
              ) : (
                <Text style={[styles.subscribeBtnText, dirText]}>
                  {isActive ? t('subscriptions.renewOrChangeBenefit') : t('subscriptions.payBenefit')}
                </Text>
              )}
            </LinearGradient>
          </TouchableOpacity>
        )}

        {isActive && !selectedPkg && (
          <Text style={[styles.renewNote, { color: mutedColor }, dirText]}>
            {t('subscriptions.renewNote')}
          </Text>
        )}
      </ScrollView>
    </SafeAreaView>
  );
}

