import { useState, useEffect, useRef, useCallback } from 'react';
import { View, Text, StyleSheet, FlatList, TextInput, TouchableOpacity, KeyboardAvoidingView, Platform, ImageBackground, Keyboard } from 'react-native';
import { SafeAreaView, useSafeAreaInsets } from 'react-native-safe-area-context';
import { router, useLocalSearchParams, useFocusEffect } from 'expo-router';
import { Ionicons } from '@expo/vector-icons';
import { LinearGradient } from 'expo-linear-gradient';
import { Colors } from '../../constants/Colors';
import { useAuthStore } from '@/store/authStore';
import { useChatStore } from '@/store/chatStore';
import api from '@/services/api';
import { getApiBaseUrl } from '@/services/api-url';
import { useTheme } from '../../context/ThemeContext';
import { io, Socket } from 'socket.io-client';
import { useAppTranslation, useLanguage } from '@/context/LanguageContext';

interface Message {
  id: string;
  senderId: string;
  text: string;
  createdAt: string;
  isRead: boolean;
}


export default function ChatDetailScreen() {
  const params = useLocalSearchParams<{
    id: string;
    listingId: string;
    otherUserId: string;
    otherUserName: string;
  }>();
  const chatId = Array.isArray(params.id) ? params.id[0] : params.id;
  const { user } = useAuthStore();
  const { chats, fetchChats } = useChatStore();
  const flatListRef = useRef<FlatList>(null);
  const { isDark } = useTheme();
  const { t } = useAppTranslation();
  const { language, isRTL } = useLanguage();
  const insets = useSafeAreaInsets();
  const chatSummary = chats.find((chat) => chat.id === chatId);
  const headerName = params.otherUserName || chatSummary?.otherUserName || t('chat.conversation');

  const theme = {
    background: isDark ? '#0f172a' : '#ECE5DD',
    card: isDark ? '#111827' : '#FFFFFF',
    text: isDark ? '#f8fafc' : '#1E293B',
    textMuted: isDark ? '#94a3b8' : '#64748B',
    border: isDark ? '#1f2937' : '#E2E8F0',
    surface: isDark ? '#1f2937' : '#F1F5F9',
    primary: Colors.primary,
  };

  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [isSending, setIsSending] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const socketRef = useRef<Socket | null>(null);
  const rowDirection = { flexDirection: 'row' as const };
  const dirText = { textAlign: 'auto' as const};

  useEffect(() => {
    const fullApiUrl = getApiBaseUrl();
    const socketUrl = fullApiUrl.replace(/\/api\/v1\/?$/, '');

    // Initialize socket connection
    socketRef.current = io(socketUrl, {
      transports: ['websocket'],
    });

    const socket = socketRef.current;

    socket.on('connect', () => {
      console.log('Socket connected');
      if (chatId) {
        socket.emit('joinRoom', { roomId: chatId });
      }
    });

    socket.on('newMessage', async (newMessage: Message) => {
      // Skip own messages — already added via optimistic UI
      if (newMessage.senderId === user?.id) return;

      setMessages((prev) => {
        if (prev.some((msg) => msg.id === newMessage.id)) {
          return prev;
        }
        return [...prev, newMessage];
      });
      setTimeout(() => {
        flatListRef.current?.scrollToEnd({ animated: true });
      }, 100);

      // Mark as read
      try {
        await api.post(`/chats/${chatId}/read`);
      } catch (error) {
        console.warn('Failed to mark message as read', error);
      }
    });

    socket.on('messagesRead', () => {
      setMessages((prev) =>
        prev.map((msg) => ({ ...msg, isRead: true }))
      );
    });

    return () => {
      if (chatId) {
        socket.emit('leaveRoom', { roomId: chatId });
      }
      socket.disconnect();
    };
  }, [chatId, user?.id]);

  useEffect(() => {
    // Scroll to bottom on mount
    setTimeout(() => {
      flatListRef.current?.scrollToEnd({ animated: false });
    }, 100);
  }, []);

  const fetchMessages = async () => {
    if (!chatId) return;
    setIsLoading(true);
    try {
      const response = await api.get(`/chats/${chatId}/messages`, { params: { page: 1, limit: 50 } });
      const data = response.data?.data || response.data;
      setMessages(Array.isArray(data) ? data : []);
    } catch (error) {
      console.warn('Failed to fetch messages', error);
    } finally {
      setIsLoading(false);
    }
  };

  useFocusEffect(
    useCallback(() => {
      fetchMessages();
      if (!params.otherUserName) {
        void fetchChats();
      }
    }, [chatId])
  );

  const sendMessage = async () => {
    if (!inputText.trim() || isSending) return;
    if (!chatId) return;

    const tempText = inputText.trim();
    setInputText('');

    const tempId = `temp_${Date.now()}`;
    const optimisticMsg: Message = {
      id: tempId,
      senderId: user?.id || '',
      text: tempText,
      createdAt: new Date().toISOString(),
      isRead: false,
    };
    setMessages(prev => [...prev, optimisticMsg]);
    setTimeout(() => flatListRef.current?.scrollToEnd({ animated: true }), 50);

    setIsSending(true);
    try {
      const response = await api.post(`/chats/${chatId}/messages`, { text: tempText });
      const message = response.data?.data || response.data;
      if (message?.id) {
        setMessages(prev => prev.map(m => m.id === tempId ? message : m));
      }
    } catch (error) {
      setMessages(prev => prev.filter(m => m.id !== tempId));
      setInputText(tempText);
      console.warn('Failed to send message', error);
    } finally {
      setIsSending(false);
    }
  };

  const formatMessageTime = (timestamp: string) => {
    const date = new Date(timestamp);
    return date.toLocaleTimeString(language === 'ar' ? 'ar-BH' : 'en-GB', { hour: '2-digit', minute: '2-digit' });
  };

  const renderMessage = ({ item }: { item: Message }) => {
    const isMyMessage = item.senderId === user?.id;

    return (
      <View
        style={[
          styles.messageContainer,
          isMyMessage ? styles.myMessageContainer : styles.theirMessageContainer,
        ]}
      >
        <View
          style={[
            styles.messageBubble,
            isMyMessage
              ? styles.myMessageBubble
              : [styles.theirMessageBubble, { backgroundColor: theme.card, borderColor: theme.border }],
          ]}
        >
          <Text
            style={[
              styles.messageText,
              isMyMessage
                ? [styles.myMessageText, dirText]
                : [styles.theirMessageText, { color: theme.text }, dirText],
            ]}
          >
            {item.text}
          </Text>
          <View style={[styles.messageFooter, rowDirection]}>
            <Text
              style={[
                styles.messageTime,
                isMyMessage ? styles.myMessageTime : [styles.theirMessageTime, { color: theme.textMuted }],
              ]}
            >
              {formatMessageTime(item.createdAt)}
            </Text>
            {isMyMessage && (
              <Ionicons
                name={item.isRead ? 'checkmark-done' : 'checkmark'}
                size={14}
                color={item.isRead ? '#3B82F6' : '#9CA3AF'}
                style={styles.checkmark}
              />
            )}
          </View>
        </View>
      </View>
    );
  };

  return (
    <SafeAreaView style={[styles.container, { backgroundColor: theme.background }]} edges={['left', 'right', 'bottom']}>
      <LinearGradient
        colors={['#0E1830', '#162444']}
        start={{ x: 0, y: 0 }}
        end={{ x: 1, y: 0 }}
        style={[styles.header, rowDirection, { paddingTop: insets.top + 12 }]}
      >
        <TouchableOpacity onPress={() => router.back()} style={[styles.backButton, { alignItems: isRTL ? 'flex-end' : 'flex-start' }]}>
          <View style={styles.backCircle}>
            <Ionicons name={isRTL ? 'arrow-forward' : 'arrow-back'} size={18} color="#D4AF37" />
          </View>
        </TouchableOpacity>
        <View style={styles.headerInfo}>
          <Text style={styles.headerName}>{headerName}</Text>
          <Text style={styles.headerStatus}>{t('chat.onlineNow')}</Text>
        </View>
        <View style={{ width: 44 }} />
      </LinearGradient>

      <KeyboardAvoidingView
        style={{ flex: 1 }}
        behavior={Platform.OS === 'ios' ? 'padding' : 'padding'}
        keyboardVerticalOffset={Platform.OS === 'ios' ? 90 : 0}
      >
        <ImageBackground
          source={{ uri: 'https://i.pinimg.com/736x/8c/98/99/8c98994518b575bfd8c943e91d8e04b4.jpg' }}
          style={styles.backgroundImage}
          resizeMode="cover"
        >
          <FlatList
            ref={flatListRef}
            data={messages}
            renderItem={renderMessage}
            keyExtractor={(item) => item.id}
            contentContainerStyle={styles.messagesContainer}
            onContentSizeChange={() => flatListRef.current?.scrollToEnd({ animated: true })}
            ListEmptyComponent={
              <View style={styles.emptyContainer}>
                <Ionicons name="chatbubbles-outline" size={48} color={theme.textMuted} />
                <Text style={[styles.emptyTitle, { color: theme.text, textAlign: 'auto'}]}>{isLoading ? t('common.loading') : t('chat.noMessages')}</Text>
                <Text style={[styles.emptyText, { color: theme.textMuted, textAlign: 'auto'}]}>{t('chat.startConversation')}</Text>
              </View>
            }
          />
        </ImageBackground>

        <View style={[
          styles.inputContainer,
          rowDirection,
          {
            backgroundColor: theme.card,
            borderTopColor: theme.border,
            paddingBottom: Math.max(insets.bottom, 16)
          }
        ]}>
          <TextInput
            style={[styles.input, { backgroundColor: isDark ? '#1f2937' : '#FFFFFF', color: theme.text, borderColor: theme.border, textAlign: 'auto'}]}
            placeholder={t('chat.messagePlaceholder')}
            value={inputText}
            onChangeText={setInputText}
            multiline
            maxLength={500}
            placeholderTextColor={theme.textMuted}
          />
          <TouchableOpacity
            style={[styles.sendButton, !inputText.trim() && styles.sendButtonDisabled]}
            onPress={sendMessage}
            disabled={!inputText.trim()}
          >
            <Ionicons name="send" size={20} color="#FFFFFF" style={{ }} />
          </TouchableOpacity>
        </View>
      </KeyboardAvoidingView>
    </SafeAreaView>
  );
}

